design_concepts.sample_css_tokens:
@import "tailwindcss";
@import "tw-animate-css";
@import "@fontsource-variable/inter";
@import "@fontsource-variable/newsreader";
@import "@fontsource-variable/newsreader/ital.css";

@custom-variant dark (&:is(.dark *));

:root {
	/* Iron Gall: dried ink on warm paper. Light is the authored theme. */
	--font-sans: "Inter Variable", ui-sans-serif, system-ui, sans-serif;
	--font-serif: "Newsreader Variable", "Iowan Old Style", Georgia, serif;
	--radius: 0.5rem;

	/* paper + ink neutrals (paper hue 84, ink hue 272; never 0-chroma, never #000/#fff) */
	--background: oklch(0.962 0.007 84);
	--foreground: oklch(0.225 0.018 272);
	--card: oklch(0.978 0.005 84);
	--card-foreground: oklch(0.225 0.018 272);
	--popover: oklch(0.978 0.005 84);
	--popover-foreground: oklch(0.225 0.018 272);
	--primary: oklch(0.45 0.105 272);
	--primary-foreground: oklch(0.972 0.005 84);
	--secondary: oklch(0.93 0.009 84);
	--secondary-foreground: oklch(0.3 0.018 272);
	--muted: oklch(0.93 0.009 84);
	--muted-foreground: oklch(0.48 0.014 272);
	--accent: oklch(0.915 0.012 84);
	--accent-foreground: oklch(0.3 0.018 272);
	--destructive: oklch(0.52 0.16 25);
	--destructive-foreground: oklch(0.972 0.005 84);
	--success: oklch(0.56 0.09 150);
	--warning: oklch(0.65 0.12 75);
	--border: oklch(0.885 0.008 84);
	--input: oklch(0.885 0.008 84);
	--ring: oklch(0.45 0.105 272);

	/* the live layer: wet ink */
	--draft: oklch(0.45 0.105 272);             /* live draft text */
	--draft-idle: oklch(0.45 0.105 272 / 0.55); /* breath held after ~6s stillness */
	--wash-draft: oklch(0.45 0.105 272 / 0.07); /* draft ground (tint wash, no stripe) */
	--wash-sent: oklch(0.925 0.014 272);        /* my sent-message wash */

	/* motion: state-conveying only */
	--ease-out-expo: cubic-bezier(0.16, 1, 0.3, 1);
	--dur-fast: 150ms;
	--dur-base: 200ms;
	--dur-slow: 250ms;
	--breath: 2400ms;

	/* fixed type scale, ratio ~1.2 */
	--text-xs: 0.75rem;
	--text-sm: 0.875rem;
	--text-base: 1.0625rem; /* message prose */
	--text-lg: 1.25rem;
	--text-xl: 1.5rem;
	--text-2xl: 1.875rem;

	--measure: 42rem; /* ~65ch of 17px serif */
}

.dark {
	/* Inkwell: the same room after dark */
	--background: oklch(0.185 0.014 272);
	--foreground: oklch(0.92 0.008 84);
	--card: oklch(0.215 0.015 272);
	--card-foreground: oklch(0.92 0.008 84);
	--popover: oklch(0.215 0.015 272);
	--popover-foreground: oklch(0.92 0.008 84);
	--primary: oklch(0.74 0.085 268);
	--primary-foreground: oklch(0.185 0.014 272);
	--secondary: oklch(0.245 0.016 272);
	--secondary-foreground: oklch(0.92 0.008 84);
	--muted: oklch(0.245 0.016 272);
	--muted-foreground: oklch(0.68 0.012 84);
	--accent: oklch(0.27 0.018 272);
	--accent-foreground: oklch(0.92 0.008 84);
	--destructive: oklch(0.68 0.14 25);
	--destructive-foreground: oklch(0.185 0.014 272);
	--success: oklch(0.72 0.10 150);
	--warning: oklch(0.78 0.11 80);
	--border: oklch(0.275 0.015 272);
	--input: oklch(0.275 0.015 272);
	--ring: oklch(0.74 0.085 268);
	--draft: oklch(0.78 0.075 268);
	--draft-idle: oklch(0.78 0.075 268 / 0.55);
	--wash-draft: oklch(0.74 0.085 268 / 0.09);
	--wash-sent: oklch(0.265 0.022 272);
}

@theme inline {
	--font-sans: var(--font-sans);
	--font-serif: var(--font-serif);
	--radius-sm: calc(var(--radius) - 4px);
	--radius-md: calc(var(--radius) - 2px);
	--radius-lg: var(--radius);
	--radius-xl: calc(var(--radius) + 4px);
	--color-background: var(--background);
	--color-foreground: var(--foreground);
	--color-card: var(--card);
	--color-card-foreground: var(--card-foreground);
	--color-popover: var(--popover);
	--color-popover-foreground: var(--popover-foreground);
	--color-primary: var(--primary);
	--color-primary-foreground: var(--primary-foreground);
	--color-secondary: var(--secondary);
	--color-secondary-foreground: var(--secondary-foreground);
	--color-muted: var(--muted);
	--color-muted-foreground: var(--muted-foreground);
	--color-accent: var(--accent);
	--color-accent-foreground: var(--accent-foreground);
	--color-destructive: var(--destructive);
	--color-destructive-foreground: var(--destructive-foreground);
	--color-success: var(--success);
	--color-warning: var(--warning);
	--color-border: var(--border);
	--color-input: var(--input);
	--color-ring: var(--ring);
	--color-draft: var(--draft);
	--color-draft-idle: var(--draft-idle);
	--color-wash-draft: var(--wash-draft);
	--color-wash-sent: var(--wash-sent);
}

@layer base {
	* {
		@apply border-border outline-ring/50;
	}
	body {
		@apply bg-background text-foreground font-sans antialiased;
	}
	/* people speak in serif; the system speaks in sans */
	.prose-message {
		font-family: var(--font-serif);
		font-size: var(--text-base);
		line-height: 1.5;
		font-optical-sizing: auto;
	}
	.prose-draft {
		font-family: var(--font-serif);
		font-style: italic;
		color: var(--draft);
	}
	time, .tabular {
		font-variant-numeric: tabular-nums;
	}
	@keyframes breath {
		0%, 100% { opacity: 0.45; }
		50% { opacity: 1; }
	}
	.breathing {
		animation: breath var(--breath) ease-in-out infinite;
	}
	@media (prefers-reduced-motion: reduce) {
		.breathing { animation: none; opacity: 1; }
	}
}
